import { createClient } from "@supabase/supabase-js"

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!

// Server-side Supabase client using service role key (bypasses RLS, works over HTTPS)
// This avoids direct TCP/IPv6 connections to the database.
function getSupabaseAdmin() {
  if (!supabaseUrl || !supabaseServiceKey) {
    throw new Error("NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY must be set.")
  }
  return createClient(supabaseUrl, supabaseServiceKey, {
    auth: { persistSession: false },
  })
}

// Tagged-template SQL emulator using Supabase's Management API SQL endpoint.
// Usage: const rows = await sql`SELECT * FROM clients WHERE org_id = ${orgId}`
// This is a drop-in replacement for postgres.js tagged template syntax.
class SqlTagError extends Error {}

type SqlValue = string | number | boolean | null | undefined | Date

function buildSql(strings: TemplateStringsArray, values: SqlValue[]): string {
  let query = ""
  strings.forEach((str, i) => {
    query += str
    if (i < values.length) {
      const val = values[i]
      if (val === null || val === undefined) {
        query += "NULL"
      } else if (typeof val === "number") {
        query += val
      } else if (typeof val === "boolean") {
        query += val ? "TRUE" : "FALSE"
      } else if (val instanceof Date) {
        query += `'${val.toISOString()}'`
      } else {
        // Escape single quotes in string values
        query += `'${String(val).replace(/'/g, "''")}'`
      }
    }
  })
  return query
}

async function executeSQL(query: string): Promise<Record<string, unknown>[]> {
  const url = `${supabaseUrl}/rest/v1/rpc`
  // Use the Management API SQL endpoint
  const apiUrl = supabaseUrl.replace("https://", "https://api.supabase.com/v1/projects/")
    .replace(".supabase.co", "") + "/database/query"

  // Try PostgREST SQL execution via service role
  const res = await fetch(`${supabaseUrl}/rest/v1/`, {
    method: "HEAD",
    headers: { apikey: supabaseServiceKey, Authorization: `Bearer ${supabaseServiceKey}` },
  })

  // Use the direct SQL API
  const sqlRes = await fetch(`${supabaseUrl}/rest/v1/rpc/exec_sql`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      apikey: supabaseServiceKey,
      Authorization: `Bearer ${supabaseServiceKey}`,
      Prefer: "return=representation",
    },
    body: JSON.stringify({ sql: query }),
  })

  if (!sqlRes.ok) {
    const err = await sqlRes.text()
    throw new SqlTagError(`SQL execution failed: ${err}`)
  }

  return sqlRes.json()
}

// Tagged template function — drop-in for postgres.js
export function sql(strings: TemplateStringsArray, ...values: SqlValue[]) {
  const query = buildSql(strings, values)
  return executeSQL(query)
}

