// Rule-Based Categorization Engine
// Matches bank transaction descriptions to categories using:
//   1. Priority-ranked keyword search (case-insensitive)
//   2. Regex pattern matching for structured strings (UPI/NEFT/IMPS etc.)
//   3. Learned user corrections stored in category_rules table
//   4. Fallback to "Uncategorized"

export interface CategoryRule {
  id: number
  category: string
  keywords: string[]
  regex_pattern: string | null
  priority: number
}

// ── Core engine ──────────────────────────────────────────────────────────────

export function categorize(description: string, rules: CategoryRule[]): {
  category: string
  source: "keyword" | "regex" | "fallback"
  matchedRule?: number
} {
  if (!description) return { category: "Uncategorized", source: "fallback" }

  // Step A: Normalize — lowercase, collapse whitespace, strip special chars
  const text = description
    .toLowerCase()
    .replace(/[\/\-_|@#]/g, " ")
    .replace(/\s+/g, " ")
    .trim()

  // Sort rules by priority descending (highest priority wins)
  const sorted = [...rules].sort((a, b) => b.priority - a.priority)

  // Step B: Regex patterns first (structured strings like UPI-/NEFT-)
  for (const rule of sorted) {
    if (rule.regex_pattern) {
      try {
        const regex = new RegExp(rule.regex_pattern, "i")
        if (regex.test(description)) {
          // Regex matched on original (preserve casing for UPI IDs etc.)
          return { category: rule.category, source: "regex", matchedRule: rule.id }
        }
      } catch {
        // Invalid regex — skip silently
      }
    }
  }

  // Step C: Keyword matching on normalized text
  for (const rule of sorted) {
    for (const kw of rule.keywords) {
      if (text.includes(kw.toLowerCase())) {
        return { category: rule.category, source: "keyword", matchedRule: rule.id }
      }
    }
  }

  // Step D: Fallback
  return { category: "Uncategorized", source: "fallback" }
}

// ── Fetch rules from DB ───────────────────────────────────────────────────────
// Imported lazily to avoid bundling DB code on the client side.

export async function fetchRules(orgId: number): Promise<CategoryRule[]> {
  const { sql } = await import("@/lib/db")
  const rows = await sql`
    SELECT id, category, keywords, regex_pattern, priority
    FROM category_rules
    WHERE org_id = ${orgId} OR org_id IS NULL
    ORDER BY priority DESC, id ASC
  `
  return rows as CategoryRule[]
}

// ── Learn from user correction ────────────────────────────────────────────────
// When a user manually changes a category, extract the most unique word from
// the description and add it as a learned keyword for that org.

export async function learnFromCorrection(
  orgId: number,
  description: string,
  correctedCategory: string
): Promise<void> {
  const { sql } = await import("@/lib/db")

  // Extract candidate keywords: words longer than 4 chars, not common filler
  const stopWords = new Set([
    "neft","rtgs","imps","upi","from","payment","paid","received","bank",
    "account","transfer","india","pvt","ltd","private","limited","towards",
    "being","with","your","this","that","have","been","will","just","more",
  ])

  const words = description
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter((w) => w.length > 3 && !stopWords.has(w))

  if (words.length === 0) return

  // Pick the most specific word (least common = longest first)
  const keyword = words.sort((a, b) => b.length - a.length)[0]

  // Upsert: add keyword to existing org rule, or create new org-level rule
  const existing = await sql`
    SELECT id, keywords FROM category_rules
    WHERE org_id = ${orgId} AND category = ${correctedCategory}
    LIMIT 1
  `

  if (existing.length > 0) {
    const rule = existing[0] as { id: number; keywords: string[] }
    if (!rule.keywords.includes(keyword)) {
      await sql`
        UPDATE category_rules
        SET keywords = array_append(keywords, ${keyword}),
            updated_at = NOW()
        WHERE id = ${rule.id}
      `
    }
  } else {
    await sql`
      INSERT INTO category_rules (org_id, category, keywords, priority, is_system)
      VALUES (${orgId}, ${correctedCategory}, ARRAY[${keyword}], 8, FALSE)
    `
  }
}

// POST /api/categorize         — categorize a single description (preview)
// POST /api/categorize/learn   — record a user correction and learn the keyword
import { sql } from "@/lib/db"
import { categorize, fetchRules, learnFromCorrection } from "@/lib/categorize"
import { NextResponse } from "next/server"

export const dynamic = "force-dynamic"

// Categorize one or many descriptions without saving
export async function POST(req: Request) {
  try {
    const { description, descriptions, org_id = 1 } = await req.json()

    const rules = await fetchRules(org_id)

    if (descriptions && Array.isArray(descriptions)) {
      const results = descriptions.map((d: string) => ({
        description: d,
        ...categorize(d, rules),
      }))
      return NextResponse.json(results)
    }

    const result = categorize(description, rules)
    return NextResponse.json({ description, ...result })
  } catch (e) {
    return NextResponse.json({ error: String(e) }, { status: 500 })
  }
}

// GET /api/categorize?org_id=1 — fetch all rules for the org
export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url)
    const orgId = parseInt(searchParams.get("org_id") || "1")

    const rules = await sql`
      SELECT id, category, keywords, regex_pattern, priority, is_system, org_id
      FROM category_rules
      WHERE org_id = ${orgId} OR org_id IS NULL
      ORDER BY priority DESC, category ASC
    `

    // Group by category for UI display
    const grouped: Record<string, { keywords: string[]; priority: number; isSystem: boolean; ruleId: number }> = {}
    for (const r of rules as { category: string; keywords: string[]; priority: number; is_system: boolean; id: number }[]) {
      if (!grouped[r.category]) {
        grouped[r.category] = { keywords: r.keywords, priority: r.priority, isSystem: r.is_system, ruleId: r.id }
      } else {
        grouped[r.category].keywords.push(...r.keywords)
      }
    }

    return NextResponse.json({ rules, grouped })
  } catch (e) {
    return NextResponse.json({ error: String(e) }, { status: 500 })
  }
}

// POST /api/categorize/learn
// Called when a user manually changes a transaction's category.
// Extracts a keyword from the description and adds it to the org's rule set.
import { sql } from "@/lib/db"
import { learnFromCorrection } from "@/lib/categorize"
import { NextResponse } from "next/server"

export const dynamic = "force-dynamic"

export async function POST(req: Request) {
  try {
    const { transaction_id, description, category, org_id = 1 } = await req.json()

    if (!description || !category) {
      return NextResponse.json({ error: "description and category are required" }, { status: 400 })
    }

    // Persist the category on the transaction
    if (transaction_id) {
      await sql`
        UPDATE bank_transactions
        SET category = ${category}, category_source = 'user'
        WHERE id = ${transaction_id}
      `
    }

    // Learn: add keyword from this description to the org's rule set
    await learnFromCorrection(org_id, description, category)

    return NextResponse.json({ success: true, message: `Learned: "${category}" for future matches` })
  } catch (e) {
    return NextResponse.json({ error: String(e) }, { status: 500 })
  }
}

