  if (!d) return ""
  return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })
}

interface PreviewProps {
  config: TemplateConfig
  invoice?: typeof SAMPLE_INVOICE
  profile?: typeof SAMPLE_PROFILE
