      <TotalsBlock inv={inv} config={config} />

      {flds.custom.filter(f => f.show).map(cf => (
        <div key={cf.id} style={{ marginTop: 4, fontSize: "11px" }}><strong>{cf.label}:</strong> {cf.value}</div>
