        </p>
      </div>
    </div>
  )
}

// Supabase OAuth callback handler.
// After Google (or any provider) signs in, Supabase redirects here with a code.
// We exchange it for a session and send the user to the dashboard.
import { NextResponse } from "next/server"
import { createServerClient } from "@/lib/supabase-auth"

export const dynamic = "force-dynamic"

export async function GET(request: Request) {
  const { searchParams, origin } = new URL(request.url)
  const code  = searchParams.get("code")
  const next  = searchParams.get("next") ?? "/dashboard"

  if (code) {
    const supabase = createServerClient()
    const { error } = await supabase.auth.exchangeCodeForSession(code)
    if (!error) {
      return NextResponse.redirect(`${origin}${next}`)
    }
  }

  // Something went wrong — send back to login with an error message
  return NextResponse.redirect(`${origin}/login?error=auth_callback_failed`)
}

"use client"
import { useState, useEffect, Suspense } from "react"
import { createBrowserClient } from "@/lib/supabase-auth"
import { useRouter, useSearchParams } from "next/navigation"
import { Eye, EyeOff, FileText, Loader2, CheckCircle } from "lucide-react"

function ResetPasswordForm() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const [password, setPw]     = useState("")
  const [confirm, setConfirm] = useState("")
  const [showPw, setShowPw]   = useState(false)
  const [loading, setLoading] = useState(false)
  const [done, setDone]       = useState(false)
  const [error, setError]     = useState(searchParams.get("error") ? "Authentication failed. Please request a new reset link." : "")

  const supabase = createBrowserClient()

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (password !== confirm) { setError("Passwords do not match"); return }
    setError(""); setLoading(true)
    try {
      const { error } = await supabase.auth.updateUser({ password })
      if (error) throw error
      setDone(true)
      setTimeout(() => router.push("/dashboard"), 2500)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to update password")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 flex items-center justify-center p-4">
