"use client"
// Handles the OAuth redirect from Google (and any future OAuth provider).
// Supabase PKCE flow: the code verifier lives in localStorage (browser),
// so the exchange MUST happen client-side.
import { useEffect, useState, Suspense } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import { createBrowserClient } from "@/lib/supabase-auth"
import { Loader2, FileText } from "lucide-react"

function CallbackHandler() {
  const router       = useRouter()
  const searchParams = useSearchParams()
  const [status, setStatus] = useState<"loading" | "error">("loading")
  const [message, setMessage] = useState("")

  useEffect(() => {
    const code  = searchParams.get("code")
    const error = searchParams.get("error")

    if (error) {
      setStatus("error")
      setMessage(searchParams.get("error_description") || "Authentication was cancelled or failed.")
      return
    }

    if (!code) {
      router.replace("/dashboard") // already signed in via magic link / implicit
      return
    }

    const supabase = createBrowserClient()
    supabase.auth.exchangeCodeForSession(code).then(({ error }) => {
      if (error) {
        setStatus("error")
        setMessage(error.message)
      } else {
        router.replace("/dashboard")
      }
    })
  }, [searchParams, router])

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 flex items-center justify-center p-4">
      <div className="text-center">
        <div className="w-12 h-12 bg-indigo-500 rounded-xl flex items-center justify-center shadow-lg mx-auto mb-4">
          <FileText className="w-6 h-6 text-white" />
        </div>

        {status === "loading" ? (
          <>
            <Loader2 className="w-6 h-6 text-indigo-400 animate-spin mx-auto mb-3" />
            <p className="text-slate-300 text-sm">Signing you in…</p>
          </>
        ) : (
          <>
            <p className="text-red-400 font-medium mb-2">Sign-in failed</p>
            <p className="text-slate-400 text-sm mb-4">{message}</p>
            <a href="/login" className="text-indigo-400 hover:text-indigo-300 text-sm underline">
              Back to login
            </a>
          </>
        )}
      </div>
    </div>
  )
}

export default function AuthCallbackPage() {
  return (
    <Suspense>
      <CallbackHandler />
    </Suspense>
  )
}

// Supabase Auth helpers using @supabase/ssr for cookie-based sessions.
// Cookie sessions work on both client AND server (middleware, layouts, API routes).
import { createBrowserClient as createSSRBrowserClient } from "@supabase/ssr"
import { createServerClient as createSSRServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { createClient } from "@supabase/supabase-js"

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL!
const ANON_KEY     = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
const SERVICE_KEY  = process.env.SUPABASE_SERVICE_ROLE_KEY!

// Browser client — stores session in cookies (readable by middleware)
export function createBrowserClient() {
  return createSSRBrowserClient(SUPABASE_URL, ANON_KEY)
}

// Server client for use in Server Components and API routes (reads cookies)
export async function createServerComponentClient() {
  const cookieStore = await cookies()
  return createSSRServerClient(SUPABASE_URL, ANON_KEY, {
    cookies: {
      getAll() { return cookieStore.getAll() },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) =>
            cookieStore.set(name, value, options)
          )
        } catch {
          // Server Component — cookies can only be set by middleware/route handlers
        }
      },
    },
  })
}

// Admin client — bypasses RLS, for server-side data operations
export function createServerClient() {
  return createClient(SUPABASE_URL, SERVICE_KEY, {
    auth: { persistSession: false },
  })
}

import { NextResponse } from "next/server"
import type { NextRequest } from "next/server"
import { createServerClient } from "@supabase/ssr"

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL!
const ANON_KEY     = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!

const PUBLIC_PATHS = ["/login", "/auth", "/onboarding", "/accept-invite", "/reset-password", "/api/"]

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Allow public paths through without auth check
  if (PUBLIC_PATHS.some((p) => pathname.startsWith(p))) {
    return NextResponse.next()
  }

  if (!pathname.startsWith("/dashboard")) {
    return NextResponse.next()
  }

  // Auth not configured — allow through (dev mode)
  if (!SUPABASE_URL || !ANON_KEY) return NextResponse.next()

  let response = NextResponse.next({ request })

  // createServerClient from @supabase/ssr reads/writes session cookies
  const supabase = createServerClient(SUPABASE_URL, ANON_KEY, {
    cookies: {
      getAll() {
        return request.cookies.getAll()
      },
      setAll(cookiesToSet) {
        // Forward any refreshed session cookies to the browser
        cookiesToSet.forEach(({ name, value }) => request.cookies.set(name, value))
        response = NextResponse.next({ request })
        cookiesToSet.forEach(({ name, value, options }) =>
          response.cookies.set(name, value, options)
        )
      },
    },
  })

  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    const loginUrl = new URL("/login", request.url)
    loginUrl.searchParams.set("redirect", pathname)
    return NextResponse.redirect(loginUrl)
  }

  return response
}

